    30→
    31→/**
    32→ * 用隐藏窗口访问目标网站，获取真实浏览器 cookies
    33→ */
    34→async function fetchCookies(url) {
    35→    return new Promise((resolve) => {
    36→        const win = new BrowserWindow({
    37→            width: 800, height: 600,
    38→            show: false,
    39→            webPreferences: { nodeIntegration: false, contextIsolation: true }
    40→        });
    41→
    42→        const timeout = setTimeout(() => {
    43→            win.destroy();
    44→            resolve();
    45→        }, 15000);
    46→
    47→        win.webContents.on('did-finish-load', () => {
    48→            setTimeout(() => {
    49→                clearTimeout(timeout);
    50→                win.destroy();
    51→                resolve();
    52→            }, 5000);
    53→        });
    54→
    55→        win.loadURL(url).catch(() => {
    56→            clearTimeout(timeout);
    57→            win.destroy();
    58→            resolve();
    59→        });
    60→    });
    61→}
