    63→/**
    64→ * 将 Electron session cookies 导出为 Netscape 格式文件
    65→ */
    66→async function exportCookies() {
    67→    const cookies = await session.defaultSession.cookies.get({});
    68→    let content = '# Netscape HTTP Cookie File\n';
    69→    for (const c of cookies) {
    70→        const domain = c.domain.startsWith('.') ? c.domain : '.' + c.domain;
    71→        const flag = 'TRUE';
    72→        const securePath = c.path || '/';
    73→        const secure = c.secure ? 'TRUE' : 'FALSE';
    74→        const expiry = c.expirationDate ? Math.floor(c.expirationDate) : '0';
    75→        content += `${domain}\t${flag}\t${securePath}\t${secure}\t${expiry}\t${c.name}\t${c.value}\n`;
    76→    }
    77→    fs.writeFileSync(COOKIES_FILE, content, 'utf-8');
    78→}
    79→
    80→/**
    81→ * 预热：获取需要 cookies 的平台
    82→ */
    83→async function warmupCookies() {
    84→    for (const [, url] of Object.entries(COOKIE_DOMAINS)) {
    85→        await fetchCookies(url);
    86→    }
    87→    await exportCookies();
    88→    console.log('Cookies 预热完成');
    89→}
