   128→function detectPlatform(url) {
   129→    url = url.toLowerCase();
   130→    if (url.includes('youtube.com') || url.includes('youtu.be')) return 'youtube';
   131→    if (url.includes('douyin.com') || url.includes('iesdouyin.com')) return 'douyin';
   132→    if (url.includes('tiktok.com')) return 'tiktok';
   133→    if (url.includes('bilibili.com')) return 'bilibili';
   134→    return 'unknown';
   135→}
