   276→async function extractDouyinInfo(url) {
   277→    try {
   278→        const rawData = await extractDouyinData(url);
   279→        const parsed = parseDouyinData(rawData);
   280→        if (parsed) {
   281→            let infoText = `📹 标题：${parsed.title || 'N/A'}`;
   282→            if (parsed.author) infoText += `\n\n👤 作者：${parsed.author}`;
   283→            if (parsed.duration) infoText += `\n⏱️ 时长：${formatDuration(parsed.duration)}`;
   284→            if (parsed.desc) infoText += `\n\n📝 描述：\n${parsed.desc.substring(0, 200)}`;
   285→            return { success: true, info: infoText, _videoUrl: parsed.videoUrl, _title: parsed.title };
   286→        }
   287→        return { success: false, error: '无法解析抖音视频数据' };
   288→    } catch (err) {
   289→        return { success: false, error: err.message };
   290→    }
   291→}
