   293→async function downloadDouyinVideo(videoUrl, title) {
   294→    const outputDir = getDesktopPath();
   295→    const safeName = (title || 'douyin_video').replace(/[<>:"/\\|?*]/g, '_').substring(0, 80);
   296→    const filePath = path.join(outputDir, `${safeName}.mp4`);
   297→
   298→    return new Promise((resolve) => {
   299→        const urlObj = new URL(videoUrl);
   300→        const client = urlObj.protocol === 'https:' ? https : http;
   301→
   302→        const reqOptions = {
   303→            hostname: urlObj.hostname,
   304→            path: urlObj.pathname + urlObj.search,
   305→            method: 'GET',
   306→            headers: {
   307→                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
   308→                'Referer': 'https://www.douyin.com/'
   309→            }
   310→        };
   311→
   312→        const req = client.request(reqOptions, (res) => {
   313→            // 跟随重定向
   314→            if (res.statusCode === 301 || res.statusCode === 302) {
   315→                const redirectUrl = res.headers.location;
   316→                if (redirectUrl) {
   317→                    downloadDouyinVideo(redirectUrl, title).then(resolve);
   318→                    return;
   319→                }
   320→            }
   321→
   322→            if (res.statusCode !== 200) {
   323→                resolve({ success: false, error: `HTTP ${res.statusCode}` });
   324→                return;
   325→            }
   326→
   327→            const fileStream = fs.createWriteStream(filePath);
   328→            let downloaded = 0;
   329→            const total = parseInt(res.headers['content-length']) || 0;
   330→
   331→            res.on('data', (chunk) => {
   332→                downloaded += chunk.length;
   333→                if (total > 0) {
   334→                    mainWindow.webContents.send('download-progress', {
   335→                        percent: (downloaded / total) * 100
   336→                    });
   337→                }
   338→            });
   339→
   340→            res.pipe(fileStream);
   341→            fileStream.on('finish', () => {
   342→                fileStream.close();
   343→                resolve({ success: true, file: filePath });
   344→            });
   345→            fileStream.on('error', (err) => {
   346→                fs.unlink(filePath, () => {});
   347→                resolve({ success: false, error: err.message });
   348→            });
   349→        });
   350→
   351→        req.on('error', (err) => resolve({ success: false, error: err.message }));
   352→        req.setTimeout(60000, () => {
   353→            req.destroy();
   354→            resolve({ success: false, error: '下载超时' });
   355→        });
   356→        req.end();
   357→    });
   358→}
