   414→async function downloadYtdlp(url, mode, platform) {
   415→    return new Promise((resolve) => {
   416→        const outputDir = getDesktopPath();
   417→        const outputTemplate = path.join(outputDir, '%(title)s.%(ext)s');
   418→        let args = [...baseArgs(platform), '--no-playlist'];
   419→
   420→        if (mode === 'audio') {
   421→            args.push('-f', 'bestaudio', '-x', '--audio-format', 'mp3', '-o', outputTemplate, url);
   422→        } else if (mode === 'video') {
   423→            args.push('-f', 'bestvideo', '-o', outputTemplate, url);
   424→        } else {
   425→            args.push('-f', 'bestvideo+bestaudio/best', '--merge-output-format', 'mp4', '-o', outputTemplate, url);
   426→        }
   427→
   428→        const proc = spawn(getYtdlp(), args);
   429→        let stderr = '';
   430→        let streamCount = 0;
   431→        let maxPercent = 0;
   432→
   433→        proc.stdout.on('data', (data) => {
   434→            const output = data.toString();
   435→            if (output.includes('Destination:')) {
   436→                streamCount++;
   437→            }
   438→            // 提取最后一个百分比（一次 data 可能包含多个）
   439→            const matches = output.match(/(\d+\.?\d*)%/g);
   440→            if (matches) {
   441→                const lastMatch = matches[matches.length - 1];
   442→                let percent = parseFloat(lastMatch);
   443→                // 双流下载时：第一个流 0-50%，第二个流 50-100%
   444→                if (streamCount >= 2) {
   445→                    percent = 50 + percent / 2;
   446→                } else if (streamCount === 1 && mode !== 'audio' && mode !== 'video') {
   447→                    percent = percent / 2;
   448→                }
   449→                if (percent > maxPercent) {
   450→                    maxPercent = percent;
   451→                    mainWindow.webContents.send('download-progress', { percent: maxPercent });
   452→                }
   453→            }
   454→            if (output.includes('Merging') || output.includes('[Merger]')) {
   455→                maxPercent = 99;
   456→                mainWindow.webContents.send('download-progress', { percent: 99 });
   457→            }
   458→        });
   459→
   460→        proc.stderr.on('data', (data) => { stderr += data.toString(); });
   461→
   462→        proc.on('close', (code) => {
   463→            resolve(code === 0 ? { success: true } : { success: false, error: stderr || '下载失败' });
   464→        });
   465→
   466→        proc.on('error', () => {
   467→            resolve({ success: false, error: 'yt-dlp 未安装，请先安装 yt-dlp' });
   468→        });
   469→    });
   470→}
